const UTC_OFFSETS = [
  ["UTC-12", "Baker Island (uninhabited)"],
  ["UTC- (PST)", "Los Angeles, Seattle, Vancouver"],
  ["UTC- (EST)", "New York, Toronto, Miami"],
  ["UTC+0 (GMT)", "London, Lisbon, Reykjavik"],
  ["UTC+1 (CET)", "Paris, Berlin, Rome, Madrid"],
  ["UTC+3 (MSK)", "Moscow, Istanbul, Riyadh"],
  ["UTC+5:30 (IST)", "Mumbai, Delhi, Kolkata"],
  ["UTC+8 (CST)", "Beijing, Singapore, Perth"],
  ["UTC+9 (JST)", "Tokyo, Seoul, Osaka"],
  ["UTC+12 (NZST)", "Auckland, Fiji"],
];

function formatInZone(date: Date, tz: string) {
  return new Intl.DateTimeFormat("en-US", { timeZone: tz, weekday: "short", year: "numeric", month: "short", day: "numeric", hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: true }).format(date);
}

export default function TimeZoneCalculator() {
  const [fromZone, setFromZone] = useState("America/New_York");
  const [toZone, setToZone] = useState("Europe/London");
  const [time, setTime] = useState(() => {
    const now = new Date();
    const pad = (n: number) => String(n).padStart(2, "0");
    return `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}T${pad(now.getHours())}:${pad(now.getMinutes())}`;
  });
  const [converted, setConverted] = useState("");

  useEffect(() => {
    try {
      const inputDate = new Date(time);
      if (isNaN(inputDate.getTime())) { setConverted(""); return; }
      setConverted(formatInZone(inputDate, toZone));
    } catch { setConverted(""); }
  }, [time, fromZone, toZone]);

  const inputFormatted = (() => {
    try { return formatInZone(new Date(time), fromZone); } catch { return ""; }
  })();

  return (
    <>
      <SEOHead
        title="Free Time Zone Calculator Online - Convert Time Between World Time Zones Instantly | CalcHive"
        description="Free online time zone calculator. Convert any time between world time zones instantly. Perfect for remote workers, travelers and international teams. 100% free, no signup required."
        canonical="/time-zone-calculator"
        keywords="free time zone calculator, time zone converter free online, convert time zones free, world time zone calculator free, free international time converter"
        category="Date & Time Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-950/50 px-3 py-1 rounded-full mb-4 inline-block">Date &amp; Time</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Time Zone Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free time zone calculator to convert time zones free for world meetings, travel, and remote work. This time zone converter free online also works as a world time zone calculator free and free international time converter.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-5 mb-8">
            <div>
              <label className="text-sm font-semibold text-foreground mb-2 block">Date &amp; Time</label>
              <input type="datetime-local" value={time} onChange={e => setTime(e.target.value)} className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 text-sm" />
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="text-sm font-semibold text-foreground mb-2 block">From Time Zone</label>
                <select value={fromZone} onChange={e => setFromZone(e.target.value)} className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 text-sm">
                  {ZONES.map(z => <option key={z.tz} value={z.tz}>{z.label}</option>)}
                </select>
              </div>
              <div>
                <label className="text-sm font-semibold text-foreground mb-2 block">To Time Zone</label>
                <select value={toZone} onChange={e => setToZone(e.target.value)} className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 text-sm">
                  {ZONES.map(z => <option key={z.tz} value={z.tz}>{z.label}</option>)}
                </select>
              </div>
            </div>
          </div>
          <motion.div key={converted} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-orange-500 to-orange-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Converted Time ({ZONES.find(z => z.tz === toZone)?.label})</p>
              <p className="text-xl font-black text-white tracking-tight" data-testid="result-converted">{converted || "-"}</p>
            </div>
            <div className="bg-accent/60 border border-border rounded-xl p-4 text-center">
              <p className="text-xs text-muted-foreground font-medium mb-1">Original Time ({ZONES.find(z => z.tz === fromZone)?.label})</p>
              <p className="text-sm font-bold text-foreground">{inputFormatted || "-"}</p>
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Convert Time Between Time Zones for Free</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["UTC Offset", "Cities / Regions"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {UTC_OFFSETS.map(([offset, cities]) => (
                  <tr key={offset} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-bold text-orange-600 dark:text-orange-400 font-mono">{offset}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{cities}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Best Free Time Zone Converter for Remote Workers and Travelers</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free date and time tool on any device to compare schedules, track durations, and get instant results without signup.</p>
          <h2 className="text-2xl font-bold text-foreground">Free World Clock and Time Zone Tool for Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free date and time tool on any device to compare schedules, track durations, and get instant results without signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/time-zone-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


